#!/usr/bin/env python###/usr/bin/env can interpret your $PATH, which makes scripts more portable.##if full path is given, e.g., !/usr/local/bin/python### this will only run your script if python is installed in /usr/local/bin.####e.g. !/Data/Programs/miniconda2/bin/python### this script was adapted to python 3.8 by Miriam Brandt on 21.02.2022# need to install Levenshtein module using python -m pip install Levenshtein commandfrom Levenshtein import *import argparseimport randomimport arrayimport timedef findTags():    parser=argparse.ArgumentParser()    parser.add_argument('-s', type = str, nargs = '*', required = True, help='Consensus anti-complementary sequence(s). Note: more than one set of tags could be designed')    parser.add_argument('-max', type = int, nargs = 1, default = [30], help='Maximum number of tag [default = 30]')    parser.add_argument('-min', type = int, nargs = 1, default = [20], help='Minimum number of tag [default = 20]')    parser.add_argument('-d', type = int, nargs = 1, default = [3], help='Minimum number of differences [default = 3]')    parser.add_argument('-i', type = int, nargs = 1, default = [0],  help='Maximum number of dinucleotide occurrences (~homopolymers) in a tag [default = 0]')    parser.add_argument('-n', type = int, nargs = 1, default = [50],  help='Maximum number of selections to be searched before querying to stop [default = 50]')    parser.add_argument('--v', action = 'store_false', default = True, help='Verbose mode (prints the intermediary tags) [default = On]')    parser.add_argument('--log', action = 'store_false', default = True, help='Write a log file with all the searches [default = On]')    parse=parser.parse_args()    args=vars(parse)    verbose = args['v']    log = args['log']    print(verbose)    minNum = args['min'][0]    maxNum = args['max'][0]    minDist = args['d'][0]    consensuses = args['s']    homo = args['i'][0]    limit = args['n'][0]    if log:        timeStamp = '-'.join(map(str, list(time.localtime())[:6]))        oLogName = 'log_%s.txt' % timeStamp        oLog = open(oLogName, 'w')    # %s acts a placeholder for a string while %d acts as a placeholder for a number.    print('Provided %s sequences from which to design %s tags:' % ((str(len(consensuses))), str(sorted(set([minNum, maxNum]))).replace(', ', '-').replace('[','').replace(']','')))    for consensus in consensuses:        print(' -', consensus)        oLog.write('%s\nConsensus sequence\t%s\n' % ('#'*30, consensus))    fastaOut = []    for consensus in consensuses:        #transforms the entered sequence into the degenerate contraries = 'y'        lenTags = len(consensus)        consensusAvoid = ''        for i in consensus:            if i == 'A':                consensusAvoid += 'B'            elif i == 'C':                consensusAvoid += 'D'            elif i == 'G':                consensusAvoid += 'H'            elif i == 'T':                consensusAvoid += 'V'            elif i == 'R':                consensusAvoid += 'Y'            elif i == 'Y':                consensusAvoid += 'R'            elif i == 'M':                consensusAvoid += 'K'            elif i == 'K':                consensusAvoid += 'M'            elif i == 'S':                consensusAvoid += 'W'            elif i == 'W':                consensusAvoid += 'S'            elif i == 'B':                consensusAvoid += 'A'            elif i == 'D':                consensusAvoid += 'C'            elif i == 'H':                consensusAvoid += 'G'            elif i == 'V':                consensusAvoid += 'T'                print('  -> to avoid sequence:', consensusAvoid)        #prepare two lists        wDinucl={}    #all candidates with dinucleotides        woDinucl=[]    #all candidates without dinucleotides        degenList =  listDegenerates(consensusAvoid)        for degenVersion in degenList:            numDinucl = 0            for degendx, degen in enumerate(degenVersion):                if degendx+1 < len(degenVersion):                    if degen == degenVersion[degendx + 1]:                        numDinucl += 1            if numDinucl == 0:                woDinucl.append(degenVersion)            elif numDinucl <= homo:                wDinucl.setdefault(numDinucl, []).append(degenVersion)        if verbose:            print()            print('Non-dinucleotidic candidates')            for idx, i in enumerate(woDinucl):                if idx == 10:                    break                print('-', i)            print()            print('Dinucleotidic candidates')            for i in sorted(wDinucl):                print('=> %d dinucleotide occurrences:' % (i))                for jdx, j in enumerate(sorted(wDinucl[i])):                    if jdx == 10:                        break                    print('-', j)        #initialize the dico 'curPercent' containing the proportion of bases for each position        curPercent = {}        for position in range(len(consensus)):            curPercent[position] = {'A':0, 'C':0, 'G':0, 'T':0}        search = 1        choice = 1        #this master loop is to validate the full tags list => if it stops: the tags are output/written        while search:            candidates_woDinucl  = list(woDinucl)            # pick a random tag from the no-dinucleotide list            rTag = random.choice(candidates_woDinucl)            #showing the first tag of the no-dinucleotide tags            if verbose:                print()                print('First random sequence:')                print('   + %s' % (rTag))                print('Selecting from non-dinucleotidic tags')            #initialize the 'selectTags' list with the random tag            selectTags = [rTag]            candidates_woDinucl.remove(rTag)            for basedx, base in enumerate(rTag):                curPercent[basedx][base] += 1            #enter a second loop which continues as long as there is tag in the 'x2' list            while 1:                subList = []                #for each of the candidate tags                for curCandi in candidates_woDinucl:                    #for each of the already selected tags                    for selectTag in selectTags:                        #check if the current candidate tag is distant enough from the current already selected tag                        if hamming(curCandi, selectTag) <= minDist:                            break                    #if the distance between the current candidate tag and all already selected tags was high enough, add it to the 'x2' list                    else:                        subList.append(curCandi)                #randomly pick a tag from the relevant candidate tags (that are distant enough from the already selected tags)                if len(subList):                    if verbose:                        showSelect(selectTags, subList, minDist, 0)                    curTag = random.choice(subList)                    if verbose:                        print('   + %s' % (curTag))                    selectTags.append(curTag)                    for basedx, base in enumerate(curTag):                        curPercent[basedx][base] += 1                    if len(selectTags) == maxNum:                        break                    candidates_woDinucl.remove(curTag)                else:                    if verbose:                        print()                        print('*'*40)                        print('No more non-dinucleotidic tag satisfying distance constraint for the current selection')                        print('*'*40)                    break            if len(selectTags) < minNum:                if homo:                    candidates_wDinucl = {}                    for w in wDinucl:                        candidates_wDinucl[w] = list(wDinucl[w])                    if verbose:                        print()                        print('Looking at dinucleotidic tag candidates:')                    while 1:                        homoResults = []                        for homoLen in sorted(candidates_wDinucl):                            subList = []                            for curCandi in candidates_wDinucl[homoLen]:                                for selectTag in selectTags:                                    if hamming(curCandi, selectTag) <= minDist:                                        break                                else:                                    subList.append(curCandi)                                    homoResults.append(curCandi)                            if verbose:                                showSelect(selectTags, subList, minDist, homoLen)                            if len(subList):                                curTag = random.choice(subList)                                if verbose:                                    print('   + %s' % (curTag))                                selectTags.append(curTag)                                for basedx, base in enumerate(curTag):                                    curPercent[basedx][base] += 1                                if len(selectTags) == maxNum:                                    break                                candidates_wDinucl[homoLen].remove(curTag)                                break                        if len(homoResults) == 0 or len(selectTags) == maxNum:                            break            search += 1            if len(selectTags) < minNum:                if verbose:                    print()                    print('#'*30)                    print('Not enough tags found.\nRestarting...')                    print('#'*30)                if search == limit:                    choice = input('\n!!! %d searches without solution !!!\nContinue? <ENTER> to stop, 1 to continue: '% (limit))                    if choice == '':                        print('\nStop searching tags for', consensus)                        break                continue            if choice == '':                continue            #############################################            ### FINAL PRINTS OF THE CURRENT SELECTION ###            #############################################            print()            print('*'*20)            print('Sequence %s (Selection %d)' % (consensus, (search-1)))            print('*'*20)            print()            print('Base composition per position:')            print('\tA\tC\tG\tT')            if log:                oLog.write('\n> Selection %d\n' % (search-1))                oLog.write('Base composition per position:\n')                oLog.write('\tA\tC\tG\tT\n')            for pos in curPercent:                curSum = sum(curPercent[pos].values())                posData = curPercent[pos]                oLog.write('%d\t%d\t%d\t%d\t%d\n' % (pos, round(float(posData['A'])/curSum, 2), round(float(posData['C'])/curSum, 2), round(float(posData['G'])/curSum, 2), round(float(posData['T'])/curSum, 2)))                print('%d\t%d\t%d\t%d\t%d' % (pos, round(float(posData['A'])/curSum, 2), round(float(posData['C'])/curSum, 2), round(float(posData['G'])/curSum, 2), round(float(posData['T'])/curSum, 2)))            #show the selected tags            if log:                oLog.write('\n==================\n')                oLog.write('%d tags selected:\n' % len(selectTags))                oLog.write('==================\n')            print()            print('==================')            print('%d tags selected:' % (len(selectTags)))            print('==================')            for tag in selectTags:                if log:                    oLog.write('%s\n' % tag)                print(tag)            print()            #ask whether the selection is OK            choice = input('Restart search/log of tags for %s? <ENTER> to stop, 1 to restart: ' % consensus)            if choice == '':                break        ##############################################        ### WRITE THE SELECTION OF TAGS (+PRIMERS) ###        ##############################################        print()        print('Sequence', consensus)        print('---------%s' % ('-'*(len(consensus))))        primerName = input('Current primer name: ')        primerSeq = input('Current primer sequence: ')        outFasta = '%s_%s_%dnt_selection%d_%s.fasta' % (primerName, consensus, lenTags, (search-1), timeStamp)        fastaOut.append(outFasta)        o = open(outFasta, 'w')        if len(selectTags)<=52:            alpha='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz'        else:            alpha=map(str, range(0, 1000))        for i, j in enumerate(sorted(selectTags)):            o.write('>%s-%s\n%s%s\n' % (primerName, alpha[i], j, primerSeq))        o.close()    print()    print('Outputs\n-------')    print('Fasta files:')    for filou in fastaOut:        print('-', filou)    if log:        print('Log file:', oLogName)def showSelect(selectTags, subList, minDist, homoLen):    '''    Simply prints the selection if verbose...    '''    #show all the already selected tags    print()    print('Already selected tags:')    for rTag in selectTags:        print('  >', rTag)    #show all the candidate tags that are distant enough from the already selected tags    if len(subList):        print('Candidate tags with >= %d edit distance to each of the %d selected tags:' % ((minDist, len(selectTags))))        if homoLen:            print('(%d-nt homopolymeric)\n ---> %s' % ((homoLen, ', '.join(subList))))        else:            print(' ---> %s' + ', '.join(subList))    else:        print('No candidate tags with >= %d edit distance to each of the %d selected tags.' % ((minDist, len(selectTags))))def listDegenerates(Seq):    '''    Lists the degenerated sequences from a IUPAC codified sequence    Return a list as follows:        for ASARA ==> [ACAAA, ACAGA, AGAAA, AGAGA]    '''    repFilename = 'iupac'    repFile = open(repFilename, "r")    # array type code c is deprecated, changing to b or u for signed character    repChars = array.array('u');        repList = list();    for line in repFile:        curChars = line.strip().split('\t')        repChars.append(curChars[0])        # array type code c is deprecated, changing to b or u for signed character        curArray = array.array('u')        for char in curChars[1:]:            if char!='-':                curArray.append(char)        repList.append(curArray)    # Parse our sequence    charIndex = 0    repPossibilities = list()    repPossibilities.append(Seq)    for char in Seq:        repIDX = 0;        replacable = -1;        for repC in repChars:            if char == repC:                replacable = repIDX            repIDX = repIDX + 1        if replacable > -1:            tmpRepPos = list()            repArray = repList[replacable]            for repSequence in repPossibilities:                for rChar in repArray:                    tmpRepPos.append(repSequence[0:charIndex] + rChar + repSequence[(charIndex + 1):])            repPossibilities = tmpRepPos        charIndex = charIndex + 1    return repPossibilitiesfindTags()